<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --panel-bg: #252525;
            --text-color: #e0e0e0;
            --accent-color: #4caf50;
            --btn-bg: #333;
            --btn-hover: #444;
        }

        body {
            margin: 0;
            padding: 20px;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            height: 100vh;
            box-sizing: border-box;
        }

        h1 { margin: 0 0 15px 0; font-size: 1.5rem; text-align: center; }

        #controls {
            display: flex;
            gap: 10px;
            margin-bottom: 10px;
            flex-wrap: wrap;
            justify-content: center;
            background: var(--panel-bg);
            padding: 10px;
            border-radius: 8px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        button {
            padding: 8px 12px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
            color: #fff;
            transition: transform 0.1s, opacity 0.2s;
            min-width: 60px;
        }

        button:hover { opacity: 0.9; transform: translateY(-1px); }
        button:active { transform: translateY(1px); }

        .btn-sand { background-color: #d4a373; color: #2c1e16; }
        .btn-water { background-color: #54a0ff; color: #1a2b4a; }
        .btn-wall { background-color: #8d99ae; color: #2c2f33; }
        .btn-acid { background-color: #e63946; color: #fff; }
        .btn-empty { background-color: #555; color: #ccc; }

        #sand-container {
            position: relative;
            margin-top: 10px;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            border-radius: 4px;
            overflow: hidden;
        }

        canvas {
            display: block;
            background-color: #111;
            cursor: crosshair;
        }

        .legend {
            margin-top: 10px;
            font-size: 0.85rem;
            color: #aaa;
            text-align: center;
        }
    </style>
</head>
<body>

    <h1>Falling Sand Sandbox</h1>

    <div id="controls">
        <button id="mat-sand" class="btn-sand" onclick="selectMaterial('sand')">Sand</button>
        <button id="mat-water" class="btn-water" onclick="selectMaterial('water')">Water</button>
        <button id="mat-wall" class="btn-wall" onclick="selectMaterial('wall')">Wall</button>
        <button id="mat-acid" class="btn-acid" onclick="selectMaterial('acid')">Acid</button>
        <button id="mat-empty" class="btn-empty" onclick="selectMaterial('empty')">Eraser</button>
        <button id="clear" style="background-color: #d32f2f;" onclick="sim.clear()">Clear All</button>
    </div>

    <div id="sand-container">
        <canvas id="sand"></canvas>
    </div>

    <div class="legend">
        Drag to paint. Walls erode with Acid. Sand sinks in Water/Acid.
    </div>

<script>
    // --- Configuration ---
    const W = 80;
    const H = 80;
    const CELL_SIZE = 5; // CSS pixels per cell

    // Materials
    const MAT_EMPTY = 'empty';
    const MAT_SAND = 'sand';
    const MAT_WATER = 'water';
    const MAT_WALL = 'wall';
    const MAT_ACID = 'acid';

    // Colors for rendering
    const COLORS = {
        [MAT_EMPTY]: '#111',
        [MAT_SAND]: '#d4a373',
        [MAT_WATER]: '#54a0ff',
        [MAT_WALL]: '#8d99ae',
        [MAT_ACID]: '#e63946'
    };

    // --- State ---
    let grid = new Array(W * H).fill(MAT_EMPTY);
    let currentMaterial = MAT_SAND;
    let isDrawing = false;
    let lastX = -1;
    let lastY = -1;

    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d');

    // --- Initialization ---
    function init() {
        // Set canvas size to match grid * cell size
        canvas.width = W * CELL_SIZE;
        canvas.height = H * CELL_SIZE;

        // Expose API on window
        window.sim = {
            w: W,
            h: H,
            tick: (n) => {
                for(let i=0; i<n; i++) update();
            },
            get: (x, y) => grid[y * W + x],
            set: (x, y, mat) => {
                if(x >= 0 && x < W && y >= 0 && y < H) {
                    grid[y * W + x] = mat;
                    draw(); // Immediate redraw for responsiveness
                }
            },
            clear: () => {
                grid.fill(MAT_EMPTY);
                draw();
            }
        };

        // Initial Draw
        draw();
    }

    // --- Rendering ---
    function draw() {
        ctx.fillStyle = COLORS[MAT_EMPTY];
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        for (let y = 0; y < H; y++) {
            for (let x = 0; x < W; x++) {
                const mat = grid[y * W + x];
                if (mat !== MAT_EMPTY) {
                    ctx.fillStyle = COLORS[mat];

                    // Add a slight border to separate cells visually
                    ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

                    // Optional: subtle inner shadow for depth
                    ctx.strokeStyle = 'rgba(0,0,0,0.1)';
                    ctx.strokeRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                }
            }
        }
    }

    // --- Simulation Logic ---
    function update() {
        // Iterate bottom-up to prevent teleporting (particles move max 1 cell per step)
        for (let y = H - 2; y >= 0; y--) {
            for (let x = 0; x < W; x++) {
                const idx = y * W + x;
                const mat = grid[idx];

                // Walls never move
                if (mat === MAT_WALL) continue;

                // Acid Logic: Erosion first, then movement
                if (mat === MAT_ACID) {
                    performErosion(x, y);
                    attemptMove(x, y, MAT_ACID);
                } 
                // Sand Logic
                else if (mat === MAT_SAND) {
                    attemptMove(x, y, MAT_SAND);
                } 
                // Water Logic
                else if (mat === MAT_WATER) {
                    attemptMove(x, y, MAT_WATER);
                }
            }
        }
    }

    function performErosion(x, y) {
        const idx = y * W + x;
        // Check neighbors: Below, Left, Right
        const neighbors = [
            { dx: 0, dy: 1 },   // Below
            { dx: -1, dy: 0 },  // Left
            { dx: 1, dy: 0 }    // Right
        ];

        for (let n of neighbors) {
            const nx = x + n.dx;
            const ny = y + n.dy;

            if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                const neighborIdx = ny * W + nx;
                const neighborMat = grid[neighborIdx];

                // Acid dissolves Sand or Wall
                if (neighborMat === MAT_SAND || neighborMat === MAT_WALL) {
                    grid[neighborIdx] = MAT_EMPTY;
                }
            }
        }
    }

    function attemptMove(x, y, type) {
        const idx = y * W + x;

        // 1. Try to move Down
        const downIdx = (y + 1) * W + x;
        if (y + 1 < H) {
            const downMat = grid[downIdx];

            // Valid targets: Empty, Water, Acid (Sand sinks in fluids)
            // Note: Walls are never valid targets for movement.
            if (downMat === MAT_EMPTY || downMat === MAT_WATER || downMat === MAT_ACID) {
                grid[idx] = downMat; // Move particle down
                grid[downIdx] = type; // Swap with target
                return; // Particle moved, done for this step
            }
        }

        // 2. Try to move Diagonally (Sand) or Sideways (Water/Acid)
        let candidates = [];

        if (type === MAT_SAND) {
            // Sand slides diagonally down-left / down-right
            candidates.push({ dx: -1, dy: 1 }); // Down-Left
            candidates.push({ dx: 1, dy: 1 }); // Down-Right
        } else {
            // Water/Acid spreads sideways
            candidates.push({ dx: -1, dy: 0 }); // Left
            candidates.push({ dx: 1, dy: 0 });  // Right
        }

        // Randomize order of checking directions
        candidates.sort(() => Math.random() < 0.5 ? 1 : -1);

        for (let cand of candidates) {
            const nx = x + cand.dx;
            const ny = y + cand.dy;

            if (nx >= 0 && nx < W && ny >= 0 && ny < H) {
                const targetIdx = ny * W + nx;
                const targetMat = grid[targetIdx];

                // Check if valid move
                if (targetMat === MAT_EMPTY || targetMat === MAT_WATER || targetMat === MAT_ACID) {
                    grid[idx] = targetMat;
                    grid[targetIdx] = type;
                    return;
                }
            }
        }
    }

    // --- Interaction ---
    function selectMaterial(mat) {
        currentMaterial = mat;
        isDrawing = false;

        // Update button styles to show selection
        document.querySelectorAll('button').forEach(b => b.style.opacity = '1');
        const activeBtn = document.getElementById(`mat-${mat}`);
        if(activeBtn) activeBtn.style.opacity = '0.7';
    }

    function getGridPos(e) {
        const rect = canvas.getBoundingClientRect();
        const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
        const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
        return { x, y };
    }

    // Mouse Events for Painting
    function startPaint(e) {
        if (currentMaterial === MAT_EMPTY) return;
        isDrawing = true;
        const pos = getGridPos(e);
        paint(pos.x, pos.y);
    }

    function movePaint(e) {
        if (!isDrawing) return;
        const pos = getGridPos(e);
        paint(pos.x, pos.y);
    }

    function endPaint() {
        isDrawing = false;
    }

    function paint(x, y) {
        if (x >= 0 && x < W && y >= 0 && y < H) {
            window.sim.set(x, y, currentMaterial);
        }
    }

    canvas.addEventListener('mousedown', startPaint);
    canvas.addEventListener('mousemove', movePaint);
    window.addEventListener('mouseup', endPaint); // Capture on window to handle drag outside canvas

    // --- Start ---
    init();

</script>
</body>
</html>
